# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests
import json

KONG_ADMIN_URL = "http://localhost:8001" # Replace with your Kong Admin URL

# --- 1. Create a Service ---
# A Service is an entity representing an external upstream API or microservice.
# It is the parent of Routes and Upstreams.
service_name = "my-example-service"
service_url = "http://mockbin.org" # The URL of your upstream API
service_data = {
    "name": service_name,
    "url": service_url,
    "retries": 5,
    "connect_timeout": 60000,
    "write_timeout": 60000,
    "read_timeout": 60000,
}

try:
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
    response.raise_for_status()
    service_config = response.json()
    print(f"Service '{service_name}' created successfully.")
    print(json.dumps(service_config, indent=2))
    service_id = service_config['id']
except requests.exceptions.RequestException as e:
    print(f"Error creating service '{service_name}': {e}")
    if e.response is not None:
        print(f"Response: {e.response.text}")
    service_id = None # Ensure service_id is not set if creation fails

# --- 2. Create a Route for the Service ---
# A Route defines how requests are matched and routed to a Service.
if service_id:
    route_name = "my-example-route"
    route_paths = ["/my-api"] # The path that Kong will listen on
    route_data = {
        "name": route_name,
        "paths": route_paths,
        "protocols": ["http", "https"],
        "methods": ["GET", "POST"],
        "service": {"id": service_id}
    }

    try:
        response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
        response.raise_for_status()
        route_config = response.json()
        print(f"\nRoute '{route_name}' created successfully for service '{service_name}'.")
        print(json.dumps(route_config, indent=2))
    except requests.exceptions.RequestException as e:
        print(f"Error creating route '{route_name}': {e}")
        if e.response is not None:
            print(f"Response: {e.response.text}")
else:
    print("\nSkipping route creation as service creation failed.")

# --- 3. Create an Upstream and Targets (for load balancing) ---
# An Upstream is a virtual hostname used to load balance requests across multiple Targets.
# Targets are the actual backend instances (IPs/hostnames and ports) of your service.
# This is an alternative to defining a 'url' directly on the Service.
# If you define an Upstream, the Service's 'host' should point to the Upstream's name.

upstream_name = "my-load-balanced-upstream"
upstream_data = {
    "name": upstream_name,
    "slots": 10, # Number of slots in the load balancer ring
    "healthchecks": {
        "active": {
            "http_path": "/",
            "timeout": 1,
            "concurrency": 10,
            "healthy": {
                "interval": 5,
                "successes": 3
            },
            "unhealthy": {
                "interval": 5,
                "timeouts": 3,
                "http_failures": 3
            }
        }
    }
}

upstream_id = None
try:
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
    response.raise_for_status()
    upstream_config = response.json()
    print(f"\nUpstream '{upstream_name}' created successfully.")
    print(json.dumps(upstream_config, indent=2))
    upstream_id = upstream_config['id']
except requests.exceptions.RequestException as e:
    print(f"Error creating upstream '{upstream_name}': {e}")
    if e.response is not None:
        print(f"Response: {e.response.text}")

if upstream_id:
    # --- Add Targets to the Upstream ---
    targets_to_add = [
        {"target": "mockbin.org:80", "weight": 100},
        {"target": "httpbin.org:80", "weight": 50} # Example of another target
    ]

    print(f"\nAdding targets to upstream '{upstream_name}'...")
    for target_data in targets_to_add:
        try:
            response = requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets", json=target_data)
            response.raise_for_status()
            target_config = response.json()
            print(f"  Target '{target_data['target']}' added successfully.")
            print(json.dumps(target_config, indent=2))
        except requests.exceptions.RequestException as e:
            print(f"  Error adding target '{target_data['target']}': {e}")
            if e.response is not None:
                print(f"  Response: {e.response.text}")

    # --- Example: Create a new Service that uses the Upstream ---
    # Note: If you use an Upstream, the Service's 'host' should be the Upstream's name.
    # The 'url' field is not used in this case, only 'host' and 'port'.
    upstream_service_name = "my-upstream-service"
    upstream_service_data = {
        "name": upstream_service_name,
        "host": upstream_name, # Point to the Upstream's name
        "port": 80, # The port Kong will use to connect to the targets
        "protocol": "http",
        "retries": 5,
        "connect_timeout": 60000,
        "write_timeout": 60000,
        "read_timeout": 60000,
    }

    try:
        response = requests.post(f"{KONG_ADMIN_URL}/services", json=upstream_service_data)
        response.raise_for_status()
        upstream_service_config = response.json()
        print(f"\nService '{upstream_service_name}' created successfully, pointing to upstream '{upstream_name}'.")
        print(json.dumps(upstream_service_config, indent=2))
        upstream_service_id = upstream_service_config['id']

        # Create a route for this new service
        upstream_route_name = "my-upstream-route"
        upstream_route_paths = ["/lb-api"]
        upstream_route_data = {
            "name": upstream_route_name,
            "paths": upstream_route_paths,
            "protocols": ["http", "https"],
            "methods": ["GET"],
            "service": {"id": upstream_service_id}
        }
        response = requests.post(f"{KONG_ADMIN_URL}/routes", json=upstream_route_data)
        response.raise_for_status()
        upstream_route_config = response.json()
        print(f"\nRoute '{upstream_route_name}' created successfully for service '{upstream_service_name}'.")
        print(json.dumps(upstream_route_config, indent=2))

    except requests.exceptions.RequestException as e:
        print(f"Error creating service '{upstream_service_name}' or its route: {e}")
        if e.response is not None:
            print(f"Response: {e.response.text}")
else:
    print("\nSkipping target and upstream service creation as upstream creation failed.")

print("\n--- Configuration script finished ---")
print(f"You can test the first service via: curl {KONG_ADMIN_URL.replace(':8001', ':8000')}/my-api")
if upstream_id:
    print(f"You can test the load-balanced service via: curl {KONG_ADMIN_URL.replace(':8001', ':8000')}/lb-api")